&#34;)); log.debug(&#34;检索到 {} 个相关文档片段&#34;, documents.size()); // 4. 构建提示词 String systemPrompt = buildSystemPrompt(); String userPrompt = buildUserPrompt(context, queryContext.candidateQueries.getFirst()); // 5. 流式调用 + 探测窗口归一化 Flux&lt;String&gt; responseFlux = chatClient.prompt() .system(systemPrompt) .user(userPrompt) .stream() .content(); log.info(&#34;开始流式输出知识库回答(探测窗口): kbIds={}&#34;, knowledgeBaseIds); return normalizeStreamOutput(responseFlux) .doOnComplete(() -&gt; log.info(&#34;流式输出完成: kbIds={}&#34;, knowledgeBaseIds)) .onErrorResume(e -&gt; { log.error(&#34;流式输出失败: kbIds={}, error={}&#34;, knowledgeBaseIds, e.getMessage(), e); return Flux.just(&#34;【错误】知识库查询失败：AI服务暂时不可用，请稍后重试。&#34;); }); } catch (Exception e) { log.error(&#34;知识库流式问答失败: {}&#34;, e.getMessage(), e); return Flux.just(&#34;【错误】知识库查询失败：&#34; + e.getMessage()); } } /** * 普通查询知识库（非流式） */ public String answerQuestion(List&lt;Long&gt; knowledgeIds, String question) { log.info(&#34;收到知识库提问: kbIds={}, question={}&#34;, knowledgeIds, question); if (knowledgeIds == null || knowledgeIds.isEmpty() || normalizeQuestion(question).isBlank()) { return NO_RESULT_RESPONSE; } // 1. 验证知识库是否存在并更新问题计数 listService.updateQuestionCounts(knowledgeIds); // 2. Query rewrite + 动态参数检索 QueryContext queryContext = buildQueryContext(question); // 3. 向量检索 List&lt;Document&gt; relevantDocs = retrieveRelevantDocs(queryContext, knowledgeIds); if (!hasEffectiveHit(question, relevantDocs)) { return NO_RESULT_RESPONSE; } // 4. 构建上下文 String context = relevantDocs.stream() .map(Document::getText) .collect(Collectors.joining(&#34;

