&#34;)); log.debug(&#34;检索到 {} 个相关文档片段&#34;, relevantDocs.size()); // 5. 构建提示词 String systemPrompt = buildSystemPrompt(); String userPrompt = buildUserPrompt(context, queryContext.candidateQueries.getFirst()); // 6. 调用大模型 try { String content = chatClient .prompt() .system(systemPrompt) .user(userPrompt) .call() .content(); content = normalizeAnswer(content); return content; } catch (Exception e) { log.error(&#34;知识库问答失败: {}&#34;, e.getMessage(), e); throw new BusinessException(ErrorCode.KNOWLEDGE_BASE_QUERY_FAILED, &#34;知识库查询失败：&#34; + e.getMessage()); } } /** * 流式输出归一化处理 * - 探测前 120 字符，快速识别&#34;无信息&#34;模板 * - 命中无信息：立即输出固定模板并结束 * - 非无信息：尽快释放缓冲并实时透传 */ private Flux&lt;String&gt; normalizeStreamOutput(Flux&lt;String&gt; rawFlux) { return Flux.create(sink -&gt; { StringBuilder probeBuffer = new StringBuilder(); AtomicBoolean passthrough = new AtomicBoolean(false); AtomicBoolean completed = new AtomicBoolean(false); final Disposable[] disposableRef = new Disposable[1]; disposableRef[0] = rawFlux.subscribe( chunk -&gt; { if (completed.get() || sink.isCancelled()) { return; } if (passthrough.get()) { sink.next(chunk); return; } probeBuffer.append(chunk); String probeText = probeBuffer.toString(); if (isNoResultLike(probeText)) { completed.set(true); sink.next(NO_RESULT_RESPONSE); sink.complete(); if (disposableRef[0] != null) { disposableRef[0].dispose(); } return; } if (probeBuffer.length() &gt;= STREAM_PROBE_CHARS) { passthrough.set(true); sink.next(probeText); probeBuffer.setLength(0); } }, sink::error, () -&gt; { if (completed.get() || sink.isCancelled()) { return; } if (!passthrough.get()) { sink.next(normalizeAnswer(probeBuffer.toString())); } sink.complete(); } ); sink.onCancel(() -&gt; { if (disposableRef[0] != null) { disposableRef[0].dispose(); } }); }); } private String normalizeAnswer(String answer) { if (answer == null || answer.isBlank()) { return NO_RESULT_RESPONSE; } String normalized = answer.trim(); if (isNoResultLike(normalized)) { return NO_RESULT_RESPONSE; } return normalized; } private boolean isNoResultLike(String text) { return text.contains(&#34;没有找到相关信息&#34;) || text.contains(&#34;未检索到相关信息&#34;) || text.contains(&#34;信息不足&#34;) || text.contains(&#34;超出知识库范围&#34;) || text.contains(&#34;无法根据提供内容回答&#34;); } private String buildUserPrompt(String context, String question) { Map&lt;String, Object&gt; map = Map.of(&#34;context&#34;, context, &#34;question&#34;, question); return userPromptTemplate.render(map); } private String buildSystemPrompt() { return sysPromptTemplate.render(); } /** * 多候选查询检索相关文档 */ private List&lt;Document&gt; retrieveRelevantDocs(QueryContext queryContext, List&lt;Long&gt; knowledgeIds) { for (String candidateQuery : queryContext.candidateQueries) { if (candidateQuery.isBlank()) { continue; } List&lt;Document&gt; docs = vectorService.similaritySearch( candidateQuery, knowledgeIds, queryContext.searchParams().topK(), queryContext.searchParams().minScore() ); log.info(&#34;检索候选 query=&#39;{}&#39;，命中 {} 条&#34;, candidateQuery, docs.size()); // 判断查询结果是否命中用户提问的核心词 if (hasEffectiveHit(candidateQuery, docs)) { return docs; } } return List.of(); } /** * 判断检索结果是否有效命中 * 通过提取中文问句的核心词进行字面匹配 */ private boolean hasEffectiveHit(String candidateQuery, List&lt;Document&gt; docs) { if (Func.isEmpty(candidateQuery) || Func.isEmpty(docs)) { return false; } String question = normalizeQuestion(candidateQuery); String coreTerm = extractCoreTerm(question).toLowerCase(); for (Document doc : docs) { String text = doc.getText(); if (!Func.isEmpty(text) &amp;&amp; text.toLowerCase().contains(coreTerm)) { return true; } } return false; } /** * 提取中文问句的核心词 * &#34;什么是进程&#34; → &#34;进程&#34; * &#34;进程是什么&#34; → &#34;进程&#34; */ private String extractCoreTerm(String question) { Matcher m = ZH_QUESTION_PREFIX.matcher(question); if (m.matches()) { return m.group(1).trim(); } m = ZH_QUESTION_SUFFIX.matcher(question); if (m.matches()) { return m.group(1).trim(); } return question; } /** * 构建查询上下文（Query Rewrite + 动态参数） */ privat